import React, {
  forwardRef,
  useImperativeHandle,
  useMemo,
  useRef,
} from "react";
import type { View } from "react-native";
import { Text } from "react-native";
import { Box } from "../../ui"; // Gluestack Box
import type { TagProps, TagSeverity } from "./Tag.types";
import { resolveThemeTokenForNative } from '../../Factory/helpers/style';
export * from './Tag.types'
const severityStyles = (
  severity: TagSeverity,
  unstyled?: boolean,
) => {
  if (unstyled) return {};

  switch (severity) {
    case "success":
      return { backgroundColor: resolveThemeTokenForNative('green.600'), color: "#fff" };
    case "warning":
      return { backgroundColor: resolveThemeTokenForNative('yellow.400'), color: "#000" };
    case "info":
      return { backgroundColor: resolveThemeTokenForNative('blue.600'), color: "#fff" };
    case "danger":
      return { backgroundColor: resolveThemeTokenForNative('red.600'), color: "#fff" };
    case "contrast":
      return { backgroundColor: "#000", color: "#fff" };
    case "secondary":
      return { backgroundColor: resolveThemeTokenForNative('gray.600'), color: "#fff" };
    default:
      return { backgroundColor: resolveThemeTokenForNative('gray.200'), color: "#000" };
  }
};

export const Tag = forwardRef<any, TagProps>((props, ref) => {
  const {
    value,
    children,
    icon,
    severity = null,
    rounded = false,
    unstyled = false,
    style,
    testID,
  } = props;

  const rootRef = useRef<View>(null);

  /**
   * PrimeReact ref API compatibility
   */
  useImperativeHandle(ref, () => ({
    getElement: () => rootRef.current,
  }));

  const content = children ?? value;

  const resolvedIcon = useMemo(() => {
    if (!icon) return null;
    return typeof icon === "function" ? icon({props}) : icon;
  }, [icon, props]);

  const colors = severityStyles(severity, unstyled);

  return (
    <Box
      ref={rootRef}
      testID={testID}

      style={{
        flexDirection:'row',
        alignItems:'center',
        paddingHorizontal:10,
        paddingVertical:4,
        borderRadius:rounded ? 999 : 6,
        backgroundColor:colors.backgroundColor,
        ...style
      }}
    >
      {resolvedIcon ? (
        <Box style={{marginRight:6}}>{resolvedIcon}</Box>
      ) : null}

      {typeof content === "string" || typeof content === "number" ? (
        <Text
          style={{
            fontSize: 12,
            fontWeight: "600",
            color: colors.color,
          }}
        >
          {content}
        </Text>
      ) : (
        content
      )}
    </Box>
  );
});

Tag.displayName = "Tag";
